29	/// Header comment above the declarations (byte-exact from every capture).
30	const HEADER: &str = "// Function signature and definition of the equational theory E";
31	
32	/// Full signature section: header comment, blank line, then the declaration
33	/// lines (`builtins:` only when it has surviving entries).
34	pub fn render(sig: &Signature) -> String {
35	    render_with(WIDTH, RIBBON, &block_doc(sig))
36	}
