38	pub(crate) fn block_doc(sig: &Signature) -> Doc {
39	    let mut lines = vec![text(HEADER), text("")];
40	    let builtin_names = builtins_line_entries(&sig.builtins);
41	    if !builtin_names.is_empty() {
42	        lines.push(fill_line(
43	            "builtins: ",
44	            builtin_names.iter().map(|n| text(n)).collect(),
45	        ));
46	    }
47	    lines.push(fill_line(
48	        "functions: ",
49	        merged_function_items(sig).iter().map(|s| text(s)).collect(),
50	    ));
51	    lines.push(equations_doc(sig));
52	    vcat(lines)
53	}
