55	/// `text prefix <> fsep (punctuate ',' items)`: comma attached to the
56	/// preceding item, fill space between items, continuation aligned after the
57	/// prefix (probe:b_all, probe:b_revealing-signing).
58	fn fill_line(prefix: &str, items: Vec<Doc>) -> Doc {
59	    beside_op(text(prefix), fsep(punctuate(&char(','), items)))
60	}
