64	/// The five builtins with a line entry, in canonical order (probe:b_all).
65	const LINE_ORDER: [&str; 5] = [
66	    "diffie-hellman",
67	    "bilinear-pairing",
68	    "multiset",
69	    "natural-numbers",
70	    "xor",
71	];
