73	fn builtins_line_entries(declared: &[String]) -> Vec<&'static str> {
74	    let mut present = [false; 5];
75	    for b in declared {
76	        match b.as_str() {
77	            "diffie-hellman" => present[0] = true,
78	            // bilinear-pairing induces diffie-hellman (probe:b_bilinear-pairing).
79	            "bilinear-pairing" => {
80	                present[0] = true;
81	                present[1] = true;
82	            }
83	            "multiset" => present[2] = true,
84	            "natural-numbers" => present[3] = true,
85	            "xor" => present[4] = true,
86	            _ => {}
87	        }
88	    }
89	    LINE_ORDER
90	        .iter()
91	        .zip(present)
92	        .filter_map(|(n, p)| p.then_some(*n))
93	        .collect()
94	}
