98	fn decl(name: &str, arity: usize, private: bool, destructor: bool) -> FunctionDecl {
99	    FunctionDecl {
100	        name: name.into(),
101	        arity,
102	        private,
103	        destructor,
104	    }
105	}
106	
107	/// `name/arity` + attribute suffix (probe:f_attrs): `private` implies a
108	/// role keyword is shown too; a public destructor shows `[destructor]` alone;
109	/// a public constructor shows nothing.
110	fn function_item(d: &FunctionDecl) -> String {
111	    let mut s = format!("{}/{}", d.name, d.arity);
112	    if d.private || d.destructor {
113	        let mut attrs: Vec<&str> = Vec::new();
114	        if d.private {
115	            attrs.push("private");
116	        }
117	        attrs.push(if d.destructor { "destructor" } else { "constructor" });
118	        s.push('[');
119	        s.push_str(&attrs.join(","));
120	        s.push(']');
121	    }
122	    s
123	}
