125	/// Base + builtin-expansion + user function symbols, deduped and byte-sorted.
126	/// Sorting the full item text equals sorting by name (`/` orders below every
127	/// identifier character), matching probe:f_sort.
128	fn merged_function_items(sig: &Signature) -> Vec<String> {
129	    let mut decls: Vec<FunctionDecl> = base_functions(&sig.builtins);
130	    for b in &sig.builtins {
131	        decls.extend(builtin_functions(b));
132	    }
133	    decls.extend(sig.functions.iter().cloned());
134	    let mut items: Vec<String> = decls.iter().map(function_item).collect();
135	    items.sort();
136	    items.dedup();
137	    items
138	}
