190	/// `sep (header : map (nest 4) (punctuate ',' eqs))`: one line when it fits,
191	/// otherwise header alone and one equation per line at indent 4
192	/// (probe:e_mid, probe:e_conv, target:Tutorial).
193	fn equations_doc(sig: &Signature) -> Doc {
194	    let header = if sig.convergent {
195	        "equations [convergent]:"
196	    } else {
197	        "equations:"
198	    };
199	    let eqs = merged_equations(sig);
200	    let mut elems = vec![text(header)];
201	    for d in punctuate(&char(','), eqs.iter().map(equation_doc).collect()) {
202	        elems.push(nest(4, &d));
203	    }
204	    sep(elems)
