207	/// `sep [lhs, nest (-2) ("= " <> rhs)]`: one line `lhs = rhs`; an overlong
208	/// equation drops `= rhs` to (equation indent − 2) (probe:e_long).
209	fn equation_doc(eq: &Equation) -> Doc {
210	    sep(vec![
211	        term::doc(&eq.lhs),
212	        nest(-2, &beside_op(text("= "), term::doc(&eq.rhs))),
213	    ])
214	}
