216	/// One-line text of an equation — the dedup/sort key (probe:e_adedup pins
217	/// byte order on this rendered text; probe:e_dup pins exact-dedup).
218	fn equation_key(eq: &Equation) -> String {
219	    render_with(isize::MAX / 2, isize::MAX / 2, &equation_doc(eq))
220	}
