222	/// Base + builtin-expansion + user equations, deduped and byte-sorted on
223	/// their rendered text.
224	fn merged_equations(sig: &Signature) -> Vec<Equation> {
225	    let mut eqs = base_equations();
226	    for b in &sig.builtins {
227	        eqs.extend(builtin_equations(b));
228	    }
229	    eqs.extend(sig.equations.iter().cloned());
230	    let mut keyed: Vec<(String, Equation)> =
231	        eqs.into_iter().map(|e| (equation_key(&e), e)).collect();
232	    keyed.sort_by(|a, b| a.0.cmp(&b.0));
233	    keyed.dedup_by(|a, b| a.0 == b.0);
234	    keyed.into_iter().map(|(_, e)| e).collect()
235	}
